const textPrompt = $('Visual Thinking5').first().json.text || '';
const webhookBody = $('Webhook').first().json.body || {};

const aspectRatio = webhookBody.aspectRatio || webhookBody.aspect_ratio || '4:5';
const colorPalette = webhookBody.color_palette || webhookBody.colorPalette || '';

function mapAspectRatioToSize(ratio) {
  const normalized = String(ratio).trim();

  // GPT Image API safe size values
  const map = {
    '1:1': '1024x1024',
    '4:5': 'auto',
    '5:4': 'auto',
    '3:4': '1024x1536',
    '4:3': '1536x1024',
    '2:3': '1024x1536',
    '3:2': '1536x1024',
    '9:16': '1024x1536',
    '16:9': '1536x1024',
  };

  return map[normalized] || 'auto';
}

const size = mapAspectRatioToSize(aspectRatio);

const mergedBinary = {};
const imageNotes = [];
let imageCount = 0;

for (const item of items) {
  const binaryData = item.binary || {};

  for (const key of Object.keys(binaryData)) {
    const newKey = `image_${imageCount}`;
    mergedBinary[newKey] = binaryData[key];

    if (key === 'material') {
      imageNotes.push(
        `[IMAGE ${imageCount + 1}: MATERIAL IMAGE] Use this as the source of truth for product, packaging, logo, brand asset, and physical details. Preserve identity accurately.`
      );
    } else if (key === 'reference') {
      imageNotes.push(
        `[IMAGE ${imageCount + 1}: STYLE REFERENCE IMAGE] Use this only for mood, layout, composition, graphic direction, and art direction. Do not copy literally.`
      );
    } else {
      imageNotes.push(
        `[IMAGE ${imageCount + 1}: ${key.toUpperCase()}] Use this image as supporting visual context.`
      );
    }

    imageCount++;
  }
}

if (imageCount === 0) {
  throw new Error('No binary images found. Please check previous node output.');
}

const prompt = `
Create a high-quality promotional advertising image.

ภาพโปรโมทโฆษณา , พร้อมรายละเอียดอ่านง่าย ไม่รกดูแล้วสบายตา ไม่ดูแน่นไปหมด มีความ Cretive มีการใช้เทคนิคด้านกราฟิกให้เหมาะสม ให้เหมาะกับประเภทของธุรกิจ ดูเป็นงานที่ดูผ่านการคัดสรรมาอย่างดี, สไตล์ภาพเหมาะกับสมัยปัจจุบัน ไม่ cyberpunk, scifi ไม่ดู AI ดูสบายตาหยุดคนดูได้

Main brief:
${textPrompt}

Brand color palette:
${colorPalette || 'Use colors that fit the brand and brief.'}

Reference image instructions:
${imageNotes.join('\n')}

Creative direction:
- Make the design clean, readable, and not overcrowded.
- Use strong visual hierarchy.
- Make it suitable for a youth-oriented audience.
- Use graphic techniques that fit the business category.
- Avoid messy layouts, excessive text, and generic AI-looking visuals.
- Preserve product/brand identity from material images.
- Use style references only for mood, composition, and art direction.
- Output aspect ratio target: 
${aspectRatio}
`.trim();

return [
  {
    json: {
      model: 'gpt-image-2',
      prompt,
      size,
      quality: 'medium',
      output_format: 'png',
      image_count: imageCount,
      has_image_1: imageCount > 1,
      has_image_2: imageCount > 2
    },
    binary: mergedBinary
  }
];

const webhookBody = $('Webhook').first().json.body || {};
const results = [];

// Normalize reference URLs
const referenceUrls = Array.isArray(webhookBody.reference_image_urls)
  ? webhookBody.reference_image_urls
  : webhookBody.reference_image_url
    ? [webhookBody.reference_image_url]
    : [];

// Normalize material URLs
const materialUrls = Array.isArray(webhookBody.material_image_urls)
  ? webhookBody.material_image_urls
  : [];

// Reference items
for (const url of referenceUrls) {
  if (!url || typeof url !== 'string' || !url.trim()) continue;

  results.push({
    json: {
      type: 'reference',
      url: url.trim(),
    }
  });
}

// Material items
for (const url of materialUrls) {
  if (!url || typeof url !== 'string' || !url.trim()) continue;

  results.push({
    json: {
      type: 'material',
      url: url.trim(),
    }
  });
}

return results;

const body = $('Webhook').first().json.body || {};

const materialUrls = Array.isArray(body.material_image_urls)
  ? body.material_image_urls
  : [];

const referenceUrls = Array.isArray(body.reference_image_urls)
  ? body.reference_image_urls
  : body.reference_image_url
    ? [body.reference_image_url]
    : [];

const output = [
  ...materialUrls.map(url => ({
    json: {
      type: 'material',
      image_url: url
    }
  })),
  ...referenceUrls.map(url => ({
    json: {
      type: 'reference',
      image_url: url
    }
  }))
];

return output;

