const mimeMap = {
  png: 'image/png',
  jpg: 'image/jpeg',
  jpeg: 'image/jpeg',
  webp: 'image/webp',
};

return items.map((item, index) => {
  const response = item.json;

  // =========================
  // 1) New format
  // response.data[0].b64_json
  // =========================
  const newImage = response?.data?.[0];

  if (newImage?.b64_json) {
    const format = (newImage.output_format || 'png').toLowerCase();
    const fileExtension = format === 'jpeg' ? 'jpg' : format;
    const mimeType = mimeMap[format] || 'image/png';

    return {
      json: {
        success: true,
        source: 'new_format',
      },
      binary: {
        data: {
          data: newImage.b64_json,
          mimeType,
          fileExtension,
          fileName: `output_${index + 1}.${fileExtension}`,
        },
      },
    };
  }

  // =========================
  // 2) Old Gemini format
  // response.candidates[0].content.parts[].inlineData
  // =========================
  const imagePart = response?.candidates?.[0]?.content?.parts?.find(
    part => part.inlineData?.data
  );

  if (imagePart) {
    const mimeType = imagePart.inlineData.mimeType || 'image/png';
    const fileExtension = mimeType.includes('jpeg')
      ? 'jpg'
      : mimeType.includes('webp')
      ? 'webp'
      : 'png';

    return {
      json: {
        success: true,
        source: 'gemini_format',
      },
      binary: {
        data: {
          data: imagePart.inlineData.data,
          mimeType,
          fileExtension,
          fileName: `output_${index + 1}.${fileExtension}`,
        },
      },
    };
  }

  return {
    json: {
      success: false,
      error: 'No image generated',
    },
  };
});
